query:
select distinct product_hierarchy_01, product_hierarchy_02, product_hierarchy_03 
FROM dim_product 
ORDER by product_hierarchy_01, product_hierarchy_02, product_hierarchy_03;

select *, anomaly_sales*1.0/total_sales as oran
from (
    select 
    sum(case when fs2.transaction_id in (select transaction_id from fact_anomaly_transaction where is_anomaly = 1) 
             then fs2.net_quantity else 0 end) anomaly_sales,
    sum(fs2.net_quantity) total_sales 
    from fact_sales fs2 
    join fact_anomaly_transaction fat on fat.transaction_id = fs2.transaction_id and fat.date_id = fs2.date_id 
    where fs2.date_id >= 20260101 
) s;
